/** Zustand store for cat management. */

import { create } from "zustand";
import { api } from "../api/client";

export interface Cat {
  id: string;
  name: string;
  displayName?: string;
  provider: string;
  avatar?: string;
  colorPrimary?: string;
  colorSecondary?: string;
  mentionPatterns?: string[];
  isAvailable: boolean;
  roles?: string[];
  evaluation?: string;
}

interface CatState {
  cats: Cat[];
  defaultCatId: string | null;
  loading: boolean;

  fetchCats: () => Promise<void>;
  getCat: (id: string) => Cat | undefined;
}

export const useCatStore = create<CatState>((set, get) => ({
  cats: [],
  defaultCatId: null,
  loading: false,

  fetchCats: async () => {
    set({ loading: true });
    try {
      const data = await api.cats.list();
      set({
        cats: data.cats,
        defaultCatId: data.defaultCat,
      });
    } finally {
      set({ loading: false });
    }
  },

  getCat: (id: string) => {
    return get().cats.find((c) => c.id === id);
  },
}));
